-- Migration: Insert March 10-31 content for dependency_freedom course
-- 22 days of content from Krishnamurti's "The Book of Life" March themes

DO $$
DECLARE
  v_system_id UUID;
BEGIN
  SELECT id INTO v_system_id FROM course_systems WHERE system_key = 'dependency_freedom';

  INSERT INTO course_contents (system_id, content_type, sequence_number, title, original_text, deep_interpretation, meditation_guide, life_practice, is_published)
  VALUES

  -- Day 10
  (v_system_id, 'daily_lesson', 10, '我们为何无法忍受"不知"？',
  E'"为什么我们总是渴望''结论''？……我们执著于某种信仰、某种观念，是因为我们害怕处于''不知道''的状态。……如果你没有任何结论，如果你对神、对政治、对未来都没有固定的看法，你会感到不安全。……但执著于结论就是老年人的标志。……只有一个年轻的、没有结论的心，才能发现真理。真理是活的，而结论是死的。"',
  E'1. **结论是安全感的拐杖**：\n我们的大脑极度厌恶"不确定性"。为了消除这种不安，我们抓取各种"结论"——"我是个好人"、"世界是残酷的"、"死后有天堂"。这些结论就像墙壁一样围住我们，给我们虚假的安全感，让我们觉得一切尽在掌握。\n2. **执著于结论即是衰老**：\n克氏给"衰老"下了一个心理学定义：**当心被结论填满时，它就老了。** 哪怕你才20岁，如果你满脑子都是固定的偏见和观念，你的心已经衰老了。相反，一个充满了好奇、时刻准备面对未知的心，才是年轻的。\n3. **真理在"不知道"中显现**：\n如果你手里紧紧抓着一张旧地图（结论），你就永远无法探索新大陆。只有当你放下地图，承认"我不知道"时，你的眼睛才能真正看到当下的路。**"不知道"不是无知，而是最高的智慧，是无限的可能性。**',
  E'**【冥想主题：安住在"我不知道"的虚空】**\n\n**准备阶段：** 找一个安静的地方坐下，背部挺直。\n\n**引导语：**\n（语速缓慢，带着一种探索未知的神秘感）\n\n"深呼吸……让呼吸带你进入内在的宁静。\n我们总是急于寻找答案，急于给一切贴上标签。\n今天，我们做一个勇敢的尝试：**放下所有的标签。**\n\n想象你此时此刻漂浮在浩瀚的宇宙真空中。\n没有上下，没有左右，没有参照物。\n问问自己：''我是谁？''\n这一次，不要用你的名字、职业、过去来回答。\n试着回答：**''我不知道。''**\n感受一下，当你说''我不知道''时，那种界限消失的感觉。\n\n再问问自己：''未来会怎样？''\n不要用计划和担忧来回答。\n试着回答：**''我不知道。''**\n看着未来像一团迷雾，充满了无限的可能。\n\n再看看你周围的世界。\n不要说''这是桌子''，''那是声音''。\n回到一种全然陌生的状态。\n**''我不知道这是什么。''**\n\n在这个''不知道''的状态里，你感到恐惧吗？\n看着那份恐惧。那是头脑失去了抓手的恐慌。\n深呼吸，穿过恐惧。\n你会发现，在恐惧的背面，是一种巨大的**自由**。\n因为''不知道''，所以你不需要防卫。\n因为''不知道''，所以你对一切保持敞开。\n\n这是一种婴儿般的状态。清澈，敏锐，充满好奇。\n你不再是一个装着陈旧知识的容器。\n你变成了感知本身。\n安住在这种''神圣的无知''中。\n不需要答案。问题本身就是答案。\n享受这份无限的轻盈……"',
  E'**【练习名称：悬置判断】**\n\n* **场景**：当你在新闻或生活中看到一件引发你情绪的事，或者听到一个观点时。\n* **惯性**：立刻下结论——"这人真坏"、"这不对"。\n* **行动**：**悬置 10 分钟**。\n* **做法**：在心里对自己说："也许还有我不知道的信息。我现在不下结论。我只观察。"\n* **体验**：感受那种"不急着站队"的心理空间，那是智慧生长的土壤。',
  true),

  -- Day 11
  (v_system_id, 'daily_lesson', 11, '逃避空虚的手段',
  E'"我们执著于财物、人或观念，这是一种逃避。……逃避什么？逃避内在那个令人惊恐的空虚。……我们用收音机、书籍、喋喋不休的谈话来填满自己。……只要我们还在通过执著来逃避空虚，我们就是恐惧的奴隶。……只有当我们停止逃避，直接面对那份空虚时，执著才会自然脱落。"',
  E'1. **填空的瘾君子**：\n我们每天不停地刷手机、听音乐、找人聊天，看似忙碌，其实是**由于恐惧**。我们害怕一旦停下来，就会面对那个巨大的、无聊的、空虚的自我。所有的执著（对人、对物、对知识），本质上都是**填充物**。\n2. **空虚不可怕，逃避才可怕**：\n我们以为那个空虚是洪水猛兽，所以拼命逃。但正是"逃避"这个动作，赋予了空虚恐怖的力量。我们越逃，它追得越紧。\n3. **面对即转化**：\n克氏告诉我们：**停下来，转身，看它。** 当你不再试图填补那个空洞，而是完全与它同在时，你会发现那个"空虚"变了。它不再是贫乏的空，而变成了**寂静的空间**。只有在空的空间里，创造力才能诞生。',
  E'**【冥想主题：坐在枯井边】**\n\n**准备阶段：** 关掉所有的声音和干扰源。\n\n**引导语：**\n"坐下来。闭上眼。\n去感受一下，此时此刻，如果没有手机，没有音乐，没有人说话……\n你的心里是什么感觉？\n是不是有一点发慌？有一点无聊？\n那种''想抓点什么''的冲动，就是你平时逃避空虚的惯性。\n\n现在，不要抓。把手放好。\n想象你的内心是一口深不见底的枯井。\n那就是你的空虚。\n以前你总是往里面扔石头、扔垃圾，想把它填满。但它永远填不满。\n今天，我们不扔东西了。\n我们只是坐在井边，往里看。\n\n看着那个黑漆漆的洞口。\n那是你生命底层的底色。\n允许那种''空荡荡''的感觉弥漫全身。\n不论是孤独感，还是无聊感，都允许它存在。\n对自己说：**''是的，我很空。这没关系。''**\n\n随着你安静地注视，奇迹发生了。\n你发现这个''空''，并不是死的。\n它是宁静的。它是广阔的。\n就像杯子只有空了才能装水，房间只有空了才能住人。\n你的空，正是你容纳万物的能力。\n\n在这个空里，没有冲突，没有噪音。\n只有纯粹的''在''。\n不要急着离开。在这份寂静的空旷中多待一会儿。\n你会发现，这才是你真正的休息。\n你不需要填满自己，你本来就是完整的空间。"',
  E'**【练习名称：戒断"背景音"】**\n\n* **场景**：做家务、开车、洗澡或走路时。\n* **惯性**：习惯性地打开播客、音乐或视频当背景音，哪怕没在听。\n* **行动**：**彻底静音**。\n* **做法**：让自己暴露在物理的沉默中。如果感到焦虑，就观察那个焦虑。告诉自己："我正在练习面对自己。"\n* **目的**：夺回对自己心智的控制权，不再做信息的被动填充者。',
  true),

  -- Day 12
  (v_system_id, 'daily_lesson', 12, '我们只活在"形象"中',
  E'"我们与人交往时，并不是与那个活生生的人交往，而是与我们心中对那个人的''形象''(Image)交往。……你对你的妻子有一个形象，她对你也有一个形象。这两个形象在互动，而不是两个人在互动。……形象是由记忆建立起来的：他曾经伤害过我，他曾经取悦过我。……只要有形象横亘在中间，真正的关系就不存在。"',
  E'1. **幽灵的社交**：\n这是人际关系最深刻的悲剧。我们并没有看见眼前的人，我们看见的是我们脑子里的**偏见和记忆**。妻子看到的是"那个不顾家的丈夫"（形象），丈夫看到的是"那个爱唠叨的妻子"（形象）。这是两个僵死的概念在打架，不是两个活人在交流。\n2. **形象是屏障**：\n形象虽然保护了我们（让我们觉得安全、可控），但也隔离了我们。由于形象的存在，我们失去了对彼此的敏感度。我们听不到对方当下的呼救，也看不到对方当下的改变。\n3. **打破形象**：\n要建立真正的关系，必须**粉碎形象**。这意味着每一刻都用全新的眼光去看对方，就像第一次见到他一样。忘掉他昨天的错误，忘掉他给你的定义。只有这样，爱才能流动。',
  E'**【冥想主题：擦拭心灵的玻璃】**\n\n**准备阶段：** 想象面前有一块布满灰尘的玻璃。\n\n**引导语：**\n"深呼吸……让心安静下来。\n在脑海中，浮现出一个你非常熟悉的人——伴侣、父母或同事。\n看着他/她的脸。\n诚实地问自己：''我真的在看他吗？还是在看我对他的印象？''\n\n想象你和这中间，隔着一块厚厚的玻璃。\n玻璃上写满了字，贴满了标签：\n''自私''、''固执''、''不理解我''、''好人''、''坏人''……\n这些都是你过去贴上去的。\n因为这层玻璃，你看不清他现在的表情，听不清他现在的声音。\n\n现在，拿起你觉知的抹布。\n我们要开始擦玻璃了。\n擦掉''他以前伤害过我''的记忆……\n擦掉''他应该怎么样''的期待……\n擦掉''他就是这种人''的定论……\n\n用力擦，直到玻璃变得透明，直到玻璃消失。\n现在，再看一眼那个人。\n没有了标签，他是谁？\n他是一个正在呼吸、正在感受、同样有恐惧和渴望的生命。\n他此刻是鲜活的，流动的。\n他可能不再是你记忆中的那个样子了。\n\n试着用心去触碰这个鲜活的生命。\n告诉他：''我愿意重新认识你。''\n''此时此刻，你是新的，我也是新的。''\n感受一下，当屏障消失时，那种直接接触的亲密感。\n这就是''关系''的重生。"',
  E'**【练习名称：撕标签】**\n\n* **行动**：今天，当那个人说话时，或者做了一件符合你"预期"的事时（比如又迟到了）。\n* **惯性**：脑子里立刻跳出："看吧，他**总是**这样！"\n* **挑战**：**删掉"总是"**。\n* **转念**："不，这是此时此刻发生的行为，不代表永远。我不给他贴标签。"\n* **尝试**：用好奇的语气问一句："今天发生了什么？"而不是用指责的语气说："你怎么又……"',
  true),

  -- Day 13
  (v_system_id, 'daily_lesson', 13, '关系是自我揭露的过程',
  E'"关系就是一面镜子。在这面镜子里，你可以看到真实的自己。……如果你能敏锐地观察自己在关系中的每一个反应——你的防御、你的攻击、你的嫉妒——这面镜子就会向你展示''我是谁''的真相。……因此，关系不是一种逃避，而是一种自我揭露的过程。"',
  E'1. **关系不是避风港，是道场**：\n我们通常想在关系里找舒服、找安慰。但克氏说，关系的真正功能是**照妖镜**。当你一个人时，你觉得自己很圣洁。但当伴侣激怒你时，你的暴力、占有欲、冷漠全都暴露了。这才是真相。\n2. **不要打碎镜子**：\n当我们看到镜子里丑陋的自己（比如嫉妒、愤怒）时，我们的本能反应是怪罪镜子（怪罪对方）："是你让我生气的！"这是在打碎镜子。\n3. **借由关系觉醒**：\n正确的态度是**感谢镜子**。对方刚才的行为，帮你把潜意识里的脓包挑破了。不要浪费这个痛苦，利用它来认识自己："为什么我会这么生气？我在保护什么？我哪里受了伤？"这就是自我揭露，这就是觉醒。',
  E'**【冥想主题：凝视镜中的真我】**\n\n**准备阶段：** 带着勇气和诚实安坐。\n\n**引导语：**\n"坐直，闭上眼。\n回想最近一次你在关系中感到不舒服的时刻——生气、委屈、嫉妒。\n那个人说了什么，或者做了什么？\n那个场景就像一面镜子，立在你面前。\n\n通常，我们盯着镜子里的人（对方），指责他。\n现在，把目光收回来。看镜子里的**你自己**。\n看着那个正在生气的你。\n看着那个正在防御的你。\n\n问问自己：''这一刻，我的痛点在哪里？''\n是因为我的自尊心受损了吗？\n是因为我害怕失去控制吗？\n是因为我觉得自己不被重视吗？\n\n不要评判自己。不要说''我不该生气''。\n只是看着。\n看清楚那个''受伤的小我''长什么样。\n正是这个冲突，让你看见了自己平时藏起来的阴影。\n这就是礼物。\n\n对着镜子里的那个对方说：''谢谢你。是你让我看到了我还需要成长的部分。''\n''我不怪你，我收回向外的指责，我开始向内疗愈。''\n深呼吸……\n当你承担起对自己情绪的责任时，你感到了力量。\n你不再是受害者，你是学习者。\n带着这份清醒，回到当下。"',
  E'**【练习名称：如果我是他】**\n\n* **场景**：当你和某人发生争执，觉得对方不可理喻时。\n* **行动**：**瞬间换位**。\n* **做法**：在心里通过那个镜子，走到对面去。想象你钻进了他的身体，拥有他的背景、他的压力、他的恐惧。\n* **提问**："如果我是他，在那种情况下，我会不会也说出同样的话？"\n* **体验**：当你真正换位时，你会发现，没有"坏人"，只有"受苦的人"。愤怒会瞬间转化为慈悲。',
  true),

  -- Day 14
  (v_system_id, 'daily_lesson', 14, '依恋就是自我孤立',
  E'"我们依恋某人，是因为我们不够完整。……我们通过依恋来填补自己，这实际上是一种自我孤立的活动。……我说''这是我的妻子''、''这是我的房子''，这堵''我的''墙，把我与其他人隔绝开了。……在依恋之中，没有爱，只有恐惧。恐惧失去，恐惧孤独。"',
  E'1. **"我的"是围墙**：\n当我们说"我的"时候，我们就在画地为牢。我们在自己周围筑起了一道墙，墙里是"我爱的"，墙外是"我不关心的"。这种**排他性**的爱，不是爱，是**孤立**。它让我们与整体的生命断开了连接。\n2. **依恋是恐惧的伪装**：\n看起来我们很深情，离不开对方。其实我们是在怕。怕什么？怕那个"我"会破碎。我们需要通过"拥有"来维持"我"的完整感。依恋越深，恐惧越深。\n3. **爱是开放的**：\n真正的爱没有围墙。它像阳光一样，照耀爱人，也照耀路人。它不抓取，所以不排他。',
  E'**【冥想主题：拆除"我的"围墙】**\n\n**准备阶段：** 想象自己坐在一圈围墙里。\n\n**引导语：**\n"闭上眼。\n想象你坐在一个城堡里，四周是高高的围墙。\n墙上写着大大的字：**''我的''**。\n我的家人，我的钱，我的成就。\n你在墙里感到很安全，但也感到很窒息，很孤独。\n你看不到墙外的风景，你也接触不到外面的人。\n\n现在，试着拆掉这堵墙。\n哪怕只是推倒一块砖。\n把''我的''这个标签撕掉。\n看着你的伴侣。他不是''你的''私有财产，他是一个属于宇宙的独立生命。\n看着你的孩子。他不是''你的''附属品，他是借由你而来的生命之箭。\n\n随着围墙的倒塌，风吹进来了，光照进来了。\n你不再是守着宝藏的吝啬鬼。\n你是敞开的。\n你的爱不再局限在那个小圈子里，它开始向外流动。\n流向邻居，流向陌生人，流向一草一木。\n\n在这种没有围墙的状态里，你不会失去任何东西。\n相反，你与整个世界重新连接了。\n感受这份没有边界的浩瀚……\n这就是从''依恋''到''大爱''的跨越。"',
  E'**【练习名称：去所有格】**\n\n* **行动**：在今天的心里对话中，试着去掉"我的"这个词。\n* **做法**：\n  * 看着伴侣，不想"我的丈夫"，想"这个正在和我生活的男人"。\n  * 看着孩子，不想"我的孩子"，想"这个正在成长的生命"。\n* **体验**：当你去掉所有格，那种控制欲和紧张感会神奇地消失，取而代之的是一种尊重和欣赏。',
  true),

  -- Day 15
  (v_system_id, 'daily_lesson', 15, '真正的责任',
  E'"你知道''责任''(Responsibility)这个词的意思吗？它的原意是''能够反应''(Response-able)。……能够对一个人的需求、痛苦、快乐做出正确、恰当的反应。……但我们现在把责任变成了义务、重担和社会压力。……如果你真的爱一个人，你对他会有自然的责任——不是因为法律规定，而是因为你对他有感觉，你对他有反应。"',
  E'1. **责任 vs 反应能力**：\n克氏还原了责任的本来面目。Responsibility = Response（反应） + Ability（能力）。责任不是这一种重担，而是一种**对当下情境做出敏锐反应的能力**。\n2. **死板的义务**：\n当我们说"我有责任养家"时，如果我们是出于死板的义务，我们的心是麻木的。我们只是在机械地给钱、做事，却没有真正的关心。\n3. **爱的反应**：\n真正的责任是：我看到你累了，我自然地去扶你；我看到你哭了，我自然地去抱你。这是**心对心的直接反应**。它不需要法律规定，也不需要道德约束。它是活的。',
  E'**【冥想主题：唤醒心的感知力】**\n\n**准备阶段：** 放松全身，让感官变得敏锐。\n\n**引导语：**\n"深呼吸……让你的心从''麻木''中苏醒过来。\n我们常常像机器人一样履行责任，却关掉了心的开关。\n现在，把那个开关打开。\n\n想象你面前有一朵花，它缺水了，叶子耷拉着。\n你给它浇水，是因为规定吗？是因为义务吗？\n不，是因为你**看见**了它的渴，你**心疼**它。\n你的浇水，是对它痛苦的自然**反应**。\n这就是真正的责任。\n\n现在，把这种感觉带到人身上。\n想到你的家人。\n不要想''我该为他们做什么''（这是义务）。\n试着去**感知**他们。\n用心去听他们此刻的状态。是累？是怕？是乐？\n当你真正感知到时，你的行动会自然流露出来。\n那也许是一个拥抱，也许是一杯热茶，也许仅仅是静静的陪伴。\n\n不需要强迫，不需要重担。\n就像手被火烫了会自动缩回一样，爱会对痛苦自动做出反应。\n让你的责任，变回这种灵敏的爱。\n感受这份轻盈的行动力……"',
  E'**【练习名称：这一刻，你需要什么？】**\n\n* **行动**：今天面对家人时，放下"我应该做什么"的清单。\n* **做法**：看着他的眼睛，真诚地问（或者在心里问）："**这一刻，你真正需要的是什么？**"\n* **反应**：也许他不需要你做饭，他只需要你听他发五分钟牢骚。满足那个真实的需求，而不是你以为的责任。',
  true),

  -- Day 16
  (v_system_id, 'daily_lesson', 16, '恐惧的终结',
  E'"只要有时间，就有恐惧。……我在想明天可能会发生什么，我在想我也许会生病、会死。……这种''想''就是时间，就是恐惧的根源。……能不能活在当下，完全不把过去和未来带入这一刻？……当心理时间停止时，恐惧就不存在了。恐惧永远是关于''不存在的事情''（未来），而不是关于''存在的事情''（当下）。"',
  E'1. **时间制造恐惧**：\n恐惧从不活在当下。你现在坐在这里，你是安全的。恐惧是你脑子里想到的"下一刻"——万一失业怎么办？万一生病怎么办？**思想制造了时间，时间制造了恐惧。**\n2. **当下无惧**：\n如果你遭遇了一只老虎，那一刻你只有行动（跑或搏斗），没有恐惧。恐惧发生在老虎还没出现（担心会遇到）或者老虎走后（后怕）。在纯粹的当下行动中，没有恐惧的容身之地。\n3. **斩断时间**：\n终结恐惧的唯一办法，是斩断心理上的"明天"。不是不计划明天，而是不从心理上担忧明天。**只活在这一秒的呼吸里。**',
  E'**【冥想主题：切断时间的导火索】**\n\n**准备阶段：** 感受当下的绝对安全。\n\n**引导语：**\n"坐好。回到呼吸。回到这个永恒的''现在''。\n想象你站在一条时间的长线上。前面是未来，后面是过去。\n恐惧就像火，顺着这条线从未来烧过来。\n\n现在，拿起你觉知的剪刀。\n在你的脚前，**咔嚓**！剪断未来的线。\n告诉自己：''我不去想下一秒。我只管这一秒的呼吸。''\n在你的脚后，**咔嚓**！剪断过去的线。\n告诉自己：''我不去想以前的失败。我只管这一秒的存在。''\n\n你现在站在一个孤岛上。这个岛叫''当下''。\n在这里，环顾四周。\n你看到了什么？只有光线，只有声音，只有身体的感觉。\n在这里，有老虎吗？没有。\n在这里，有饥饿吗？没有。\n在这里，有被抛弃吗？没有。\n\n在这一秒里，你是绝对安全的。\n恐惧是头脑对未来的投影。而当下没有投影。\n尽可能长时间地，在这个''没有时间''的孤岛上休息。\n每当恐惧袭来，就挥动剪刀——''剪断！回来！''\n感受这种切断时间后的深层宁静。\n你就在这里。这就足够了。"',
  E'**【练习名称：一步一脚印】**\n\n* **场景**：当你面对一个巨大的任务或挑战，感到焦虑害怕时。\n* **行动**：**极度短视**。\n* **做法**：不要看终点。只看脚下这**一步**。\n  * 不要想"怎么写完这本书"，只想"怎么写好这一句"。\n  * 不要想"怎么还完房贷"，只想"怎么做好今天的工作"。\n* **体验**：当你把视野缩短到"当下这一步"时，恐惧就失去了附着点。你只剩下行动的力量。',
  true),

  -- Day 17
  (v_system_id, 'daily_lesson', 17, '逃避不仅没用，反而更危险',
  E'"我们大部分人都在逃避恐惧。我们用工作、娱乐、神、理想或某种社会活动来掩盖恐惧。……但是逃避并不能解决恐惧，它只是把恐惧藏到了更深的地方。……不仅如此，逃避本身甚至比恐惧更可怕。因为逃避会制造出分裂、矛盾和神经质的紧张。……如果你不再逃避，而是直接面对恐惧，你会发现恐惧本身其实并没有那么可怕，可怕的是那颗想要逃跑的心。"',
  E'1. **逃避的机制 (The Mechanism of Escape)**：\n当恐惧（比如孤独、失败、死亡）袭来时，我们的本能反应是"转头"。我们立刻打开电视，或是沉溺于工作，或是去寻求宗教慰藉。这种"转头"的动作，就是逃避。我们建立了一整套复杂的防御工事（生活方式）来确保自己看不见恐惧。\n2. **逃避制造了双重痛苦**：\n克氏指出一个深刻的心理事实：**"逃避"这个动作本身，比恐惧本身更耗能。** 你为了维持防御工事，必须时刻保持紧张和警惕。这种长期的防御姿态，导致了我们的焦虑和神经衰弱。\n3. **直面即解脱**：\n如果你停止逃跑，转过身来，直接看着那个让你害怕的东西，你会发现什么？你会发现它只是一个念头，或者是身体的一种感觉。它没有牙齿，它咬不到你。是你对它的"想象"和"逃跑"赋予了它力量。',
  E'**【冥想主题：在恐惧面前的一百八十度转身】**\n\n**准备阶段：** 找一个不受打扰的地方坐下。\n\n**引导语：**\n"深呼吸……让身体安顿下来。\n现在，去捕捉你内心那个想''逃''的冲动。\n也许你现在就想拿起手机，也许你想去吃点东西，也许你想想点快乐的事。\n这种躁动，就是逃避。\n\n现在，在心里做一个坚定的决定：**我不跑了。**\n想象你正走在一条黑暗的巷子里，感觉身后有个怪物（恐惧）在追你。\n你拼命跑，心跳加速，恐惧到了极点。\n现在，停下脚步。\n深吸一口气，做一百八十度转身。\n正面面对那个追你的东西。\n\n在你的觉知之光下，看清它是什么。\n它可能是一团黑雾，可能是一个记忆的片段，可能只是一种胃部收紧的感觉。\n看着它。不眨眼地看着它。\n问它：''你想对我做什么？''\n你会发现，当你不再逃跑时，那个怪物愣住了。它开始缩小。\n因为它只是影子的集合，它依靠你的恐惧而生。\n你不怕了，它就消失了。\n\n试着向它走近一步。再走近一步。\n直到你穿过它。\n原来那里什么都没有。\n感受这一刻的释然。你不需要再跑了。你可以停下来休息了。\n这就是勇气的滋味。\n安住在''不再逃避''的安稳中……"',
  E'**【练习名称：拥抱"微恐惧"】**\n\n* **行动：** 今天刻意不做某件你习惯用来"压惊"的事。\n* **做法：**\n  * 如果你习惯一回家就开电视（怕家里太安静），**今天不开**。\n  * 如果你习惯走路听歌（怕脑子空下来），**今天摘掉耳机**。\n* **观察：** 就在那个安静、空虚、甚至有点发毛的时刻，对自己说："**我在练习不逃避。我看着这份不安。**" 坚持10分钟，你会发现那份不安会自动平息。',
  true),

  -- Day 18
  (v_system_id, 'daily_lesson', 18, '一旦命名，你就看不见它了',
  E'"当一种感觉生起时，我们立刻给它贴上标签，给它命名：''这是恐惧''、''这是愤怒''。……请注意，这个命名(Naming)的过程是非常危险的。……因为一旦你给了它一个名字，你就把它归类到了旧的记忆档案里。你就不是在看''新的感觉''，而是在看''旧的词汇''。……文字和标签变成了你和感觉之间的屏障。能不能只观察感觉，而不给它命名？"',
  E'1. **语言的屏障**：\n"恐惧"这个词，不是恐惧本身。就像"水"这个字，解不了你的渴。当我们说"我很害怕"时，我们的大脑迅速调用了过去关于"害怕"的所有糟糕记忆，并将它们叠加在当下的感觉上。这让当下的感觉变得比实际上更可怕。\n2. **旧瓶装新酒**：\n每一刻的感觉都是新的、独特的。但当我们用旧的标签（如"焦虑"）去框住它时，我们就停止了对它的直接感知。我们把活的感觉变成了死的概念。\n3. **非语言的观察**：\n克氏教导我们一种极高的观察技巧：**不论断，不命名。** 就像婴儿第一次看到火，他没有"火"这个概念，他只是感受到光和热。当我们去掉"恐惧"这个标签，只剩下纯粹的生理觉受（心跳快、手抖）时，那个心理上的恐怖感就消失了。',
  E'**【冥想主题：回到前语言时代】**\n\n**准备阶段：** 放松大脑的语言中心。\n\n**引导语：**\n"坐直。闭上眼。\n现在，让那个让你不舒服的感觉浮现出来。\n你的头脑立刻会说：''这是焦虑''，或者''这是压力''。\n现在，想象你是一个还没有学会说话的婴儿。\n你不懂任何词汇。你不知道什么叫''焦虑''。\n\n现在，再去看那个感觉。\n你看到了什么？\n你可能感觉到胸口有一团能量在振动。\n你可能感觉到腹部有一种紧缩的节奏。\n你可能感觉到呼吸变得急促。\n\n这只是一股能量流。\n它是热的吗？它是刺痛的吗？它是流动的吗？\n带着好奇心去研究这股能量的质地。\n不要用词语去定义它。一旦头脑想说''我怕''，就让这个词飘走。\n回到直接的身体触感。\n\n当你拿走''恐惧''这个标签后，这股能量还可怕吗？\n不，它只是一股强烈的生命感觉。\n它甚至带着一种兴奋的颤动。\n你把一只''老虎''还原成了一只''猫''。\n这就是非语言观察的力量。\n安住在这种纯粹的感知中……"',
  E'**【练习名称：把"形容词"变成"动词"】**\n\n* **行动：** 当你感到情绪波动时，改变你的内心独白。\n* **转化：**\n  * 不要说："我很**悲伤**（名词/标签）。"\n  * 要说："我的胸口**感觉**沉重，我的眼睛**想要**流泪（动词/事实）。"\n  * 不要说："我很**生气**。"\n  * 要说："我的体温**在升高**，我的呼吸**在变粗**。"\n* **体验：** 当你描述事实而非贴标签时，你就是客观的观察者，情绪就无法淹没你。',
  true),

  -- Day 19
  (v_system_id, 'daily_lesson', 19, '分析是另一种形式的懒惰',
  E'"我们以为通过分析恐惧的起因，就能消除恐惧。……我们花几年时间去分析童年，分析梦境。……但分析是恐惧的终结吗？不是。分析需要时间，而在分析的过程中，恐惧依然存在。……而且，分析者本身就是受制约的，他怎么能通过有偏见的分析来解脱呢？……我们需要的是当下的直接觉知，而不是漫长的智力分析。"',
  E'1. **分析的陷阱**：\n心理分析往往是一个无限倒退的过程："我怕这个是因为童年阴影，童年阴影是因为父母，父母是因为社会……"这种因果挖掘也许能满足智力好奇，但它**不能在当下止息痛苦**。知道伤口是怎么来的，并不能让伤口愈合。\n2. **分析者即是被分析者**：\n谁在分析？还是那个困惑、恐惧的"我"。用一个受损的仪器（我）去修理由受损仪器产生的问题（恐惧），怎么可能修得好？这就像警察和窃贼是同一个人。\n3. **觉知是即刻的**：\n克氏强调**"看" (Seeing)** 而非"想" (Thinking)。当你打开灯，黑暗**立刻**消失。你不需要分析黑暗的成分、历史和起因。觉知就是那盏灯。只要你在当下全神贯注地看着恐惧，恐惧就会在光中化解。这是**顿悟**，不需要时间。',
  E'**【冥想主题：扔掉手术刀，打开探照灯】**\n\n**准备阶段：** 停止大脑的思考模式。\n\n**引导语：**\n"深呼吸……让头脑那些复杂的齿轮停下来。\n我们习惯了当心理医生，拿着手术刀解剖自己：''为什么我会这样？''''这说明了什么？''\n现在，把手术刀扔掉。\n这种智力游戏救不了你。\n\n现在，只要做一件事：**打开灯。**\n把你的觉知想象成一束强力的探照灯。\n直接照向你内心那个阴暗的角落——那个让你不安的地方。\n不要问''为什么这里有阴影？''\n只是照着它。\n\n看着那个不安。\n它是圆的还是扁的？是动的还是静的？\n全力以赴地看着它，就像看着草丛里的一条毒蛇。\n当你全神贯注时，你还有空去分析吗？\n没有。你的全部能量都在''看''上。\n就在这高强度的''看''之中，那是没有过去、没有未来的。\n恐惧因为被完全看见，而失去了神秘感和控制力。\n它就在光中消融了。\n保持这种高强度的注视。不分析，只觉知。\n这就是解脱的捷径。"',
  E'**【练习名称：禁止问"为什么"】**\n\n* **行动：** 今天，当你陷入负面情绪时。\n* **禁令：** 严禁问自己"**为什么**我会这样？"（这会把你带入无尽的分析）。\n* **替代：** 只问自己"**现在**发生了什么？"\n  * "现在我的胃在痛。"\n  * "现在我有一个想逃跑的念头。"\n* **目的：** 把能量从"挖掘过去"转移到"觉知当下"。',
  true),

  -- Day 20
  (v_system_id, 'daily_lesson', 20, '观察者就是被观察者',
  E'"只要有一个观察者（我）在看着恐惧，并试图以此来做些什么，冲突就永远不会结束。……观察者说：''我很怕。''这里面有二元对立：一个是''我''，另一个是''恐惧''。……但那个观察者是谁？他难道不就是恐惧本身吗？……是恐惧制造了这个''想要逃避恐惧的我''。……当你领悟到观察者就是被观察者时，所有的挣扎都结束了。"',
  E'这是克氏最核心、最深奥，也最具有转化力的教导。\n\n1. **二元对立的幻觉**：\n我们总觉得："我"（好的、想变好的）在这里，看着对面的"恐惧"（坏的、要被消灭的）。这种**分离**让我们与恐惧开战。我们想压制它、消灭它。这场战争本身就是痛苦。\n2. **同根同源**：\n那个说"我要消灭恐惧"的"我"，其实也是由恐惧制造出来的。是因为怕，所以想消灭。所以，**"想消灭恐惧的念头"本身就是恐惧的一部分。**\n3. **合一的寂静**：\n当你突然看清：**根本没有一个独立于恐惧之外的"我"**，我就是这一团恐惧，我就是这个感觉本身。那一刻，你就不再挣扎了。既然我就是恐惧，我还能逃到哪里去？我还能跟谁打仗？\n在这种彻底的放弃抵抗、彻底的合一中，能量不再消耗于内战，而是转化为纯粹的觉知。恐惧随之发生质变，成为单纯的能量。',
  E'**【冥想主题：水溶于水】**\n\n**准备阶段：** 这是一个深度的合一练习。\n\n**引导语：**\n"坐稳。闭上眼。\n让那种恐惧或焦虑的感觉浮现出来。\n想象它是一团深蓝色的墨水，滴在了一杯清水里。\n你通常觉得自己是那杯清水，想把墨水赶出去。\n这是不可能的。\n\n现在，放弃这个努力。\n对自己说：**''我不是看墨水的人，我就是那团墨水。''**\n试着完全进入那种焦虑的感觉里。\n不要作为旁观者去观察它，而是作为它去存在。\n说：''我就是焦虑本身。''\n\n当你和焦虑完全重合时，谁在抗拒谁？\n没有了。\n没有了''我想摆脱它''，因为我就是它。\n没有了''我很痛苦''，因为没有一个受害者，只有这种状态。\n\n在这个合一的瞬间，去感受那种突然降临的寂静。\n虽然能量还在波动，但冲突停止了。\n就像一滴水融入大海，你融入了你的体验。\n不再分裂。\n在这份完整的存在中，恐惧转化为了宁静的生命之流。\n安住于''一''，而非''二''……"',
  E'**【练习名称：消除主语】**\n\n* **行动：** 当你感到害怕或愤怒时，修改你的心理语言。\n* **做法：** 去掉主语"我"。\n  * 不要说："**我**很害怕。"（这创造了我和恐惧的对立）。\n  * 要说："**恐惧**在这里。" 或者 "**恐惧**正在发生。"\n* **进阶：** 甚至只说："**是恐惧。**"\n* **体验：** 这会帮助你打破"我受苦"的幻觉，只留下纯粹的现象。',
  true),

  -- Day 21
  (v_system_id, 'daily_lesson', 21, '恐惧的根源是思想',
  E'"思想是恐惧的根源。……思想思考着未来，思考着痛苦，思考着死亡。……思想创造了时间，而时间就是恐惧。……只要思想在运作，恐惧就不可避免。……但这并不意味着我们要停止思考，变成傻瓜。而是我们要觉知到思想的局限，让思想在不需要它的时候止息。"',
  E'1. **思想制造危险**：\n现实中可能并没有危险（你现在坐在屋子里很安全），但思想制造了危险："万一明天地震怎么办？""万一我老了没钱怎么办？"这些画面都是思想编织的，身体却会对这些虚构的画面产生真实的恐惧反应。\n2. **时间的诅咒**：\n思想只能在时间中运作（过去和未来）。恐惧永远寄生在"明天"。如果你完全活在"此时此刻"，没有过去和未来，恐惧能依附在哪里？\n3. **正确使用思想**：\n我们不是要消灭思想（那样无法生活），而是要让思想**归位**。处理技术问题时使用思想，但在心理层面，保持活在当下。不要让思想这匹野马，把我们拖进未来的悬崖。',
  E'**【冥想主题：看着念头的生灭】**\n\n**准备阶段：** 像一个守门人一样警觉。\n\n**引导语：**\n"坐直。把注意力集中在脑海的屏幕上。\n我们来抓那个制造恐惧的''罪魁祸首''——念头。\n\n保持警惕，像猫守在老鼠洞口。\n看，一个念头冒出来了：''明天那个会议怎么办？''\n立刻觉察它。\n告诉自己：''这是一个念头。这是一张关于未来的图片。这不是现实。''\n看着这个念头，像肥皂泡一样，飘起来……破了。\n\n又一个念头来了：''要是他不喜欢我怎么办？''\n觉察它。\n''这是思想在编故事。此刻，这里只有我。''\n看着它消散。\n\n你会发现，恐惧不是一个实体，它是由这一个个念头串起来的链条。\n当你用觉知斩断每一个念头时，恐惧的链条就断了。\n在两个念头之间，有一个微小的空隙。\n那是没有思想、没有时间、也没有恐惧的空隙。\n试着把这个空隙拉长……再拉长……\n安住在这个无念的空白中。这就是绝对的安全。"',
  E'**【练习名称：这是事实，还是想法？】**\n\n* **行动：** 当你感到焦虑时，拿出一张纸。\n* **做法：** 把让你焦虑的事写下来。然后分辨：\n  * **事实**："老板刚才皱了眉。"（这是事实）\n  * **想法**："他肯定对我不满，我要被开除了，我还要还房贷……"（这是思想制造的恐惧）。\n* **切断：** 划掉那些"想法"，只保留"事实"。对着事实，你往往能从容应对。',
  true),

  -- Day 22
  (v_system_id, 'daily_lesson', 22, '面对哀伤',
  E'"我们不了解哀伤(Sorrow)。我们因为失去、因为孤独、因为得不到爱而哀伤。……哀伤总是伴随着自怜。……只要有''我''，就有哀伤。……如果你不逃避哀伤，不试图合理化它，而是全心全意地与它同在，你会发现，哀伤中蕴含着巨大的激情(Passion)。"',
  E'1. **自怜的眼泪**：\n我们大部分的悲伤，其实是**自怜**。"我真可怜"、"为什么我失去了他"。这是一种以自我为中心的收缩。\n2. **哀伤的转化**：\n克氏提出了一个惊人的观点：**哀伤是爱的背面。** 当我们逃避哀伤时，我们的心变冷了，变得迟钝。但如果我们敢于彻底拥抱哀伤，这股巨大的能量会洗刷我们的心，让心变得极度敏感、柔软。\n3. **受难与重生**：\n不要急着擦干眼泪，不要急着寻求安慰。留在那个痛里。当你完全与痛合一，痛就失去了"我受苦"的那个"我"，只剩下纯粹的**爱与慈悲**。这就是从Sorrow（哀伤）到Passion（激情/受难）的转化。',
  E'**【冥想主题：雨中的拥抱】**\n\n**准备阶段：** 允许自己脆弱。\n\n**引导语：**\n"坐下来，甚至可以蜷缩起来。\n触碰你心底的那份悲伤。也许是失去某人的痛，也许是生而为人的孤独。\n它像一场冷雨，淋湿了你的心。\n\n不要撑伞（不要防御）。不要躲进屋里（不要逃避）。\n就站在雨里。\n感受那份冰凉，那份刺痛，那份想哭的冲动。\n允许眼泪流下来。\n这不是软弱，这是你在触碰生命的真相。\n\n试着去拥抱这份悲伤。像母亲拥抱一个哭泣的婴儿。\n不为了让他不哭，只是为了陪着他。\n当你全然地接纳这份痛时，你会发现，心里的硬块融化了。\n一种深深的温柔从伤口处涌出来。\n因为懂得了痛，你懂得了众生的苦。\n你的心变得无限宽广，无限慈悲。\n雨停了。空气被洗刷得格外清新。\n这就是哀伤的礼物——一颗柔软而敏感的心。"',
  E'**【练习名称：不寻求安慰】**\n\n* **场景：** 当你感到难过时。\n* **惯性：** 找朋友吐槽求安慰，或者吃甜食让自己开心。\n* **挑战：** **独自消化**。\n* **心法：** 告诉自己："这份悲伤是神圣的，我要自己品尝它，而不是把它稀释掉。"\n* **体验：** 哪怕只有半小时，独自与悲伤待在一起。你会发现你从悲伤中获得了力量，而不是被它打败。',
  true),

  -- Day 23
  (v_system_id, 'daily_lesson', 23, '智慧是恐惧的终结',
  E'"只有智慧(Intelligence)能终结恐惧。……智慧不是知识，不是书本上的理论。……智慧是对真相的瞬间洞察。……当你看到悬崖，你不需要思考就会立刻止步，这就是智慧。……当你看到恐惧的整个结构——它是如何由时间、思想、自我制造出来的——就在那个''看到''的瞬间，恐惧就结束了。"',
  E'1. **智慧 vs 知识**：\n知识是死的积累，智慧是活的感知。对付恐惧，不需要学很多心理学知识，只需要你有一双**能看清真相的眼睛**。\n2. **看清即行动**：\n这是克氏最著名的教导。**"看"就是行动。** 当你真的看见了"火是烫的"，你自然不会去摸。当你真的看见了"恐惧是思想制造的幻觉"，恐惧自然就吓不到你。你不需要努力去消除它，它自己就脱落了。\n3. **觉醒的瞬间**：\n恐惧的终结不是一个漫长的修炼过程，而是一个**顿悟**。就在你看清它的那一秒，你就自由了。',
  E'**【冥想主题：打开灯，噩梦终结】**\n\n**准备阶段：** 带着一种清醒的决断力。\n\n**引导语：**\n"坐直。让我们做最后的清理。\n恐惧就像屋子里的鬼影，让你瑟瑟发抖。\n你试图和鬼谈判，试图锻炼胆量，都没用。\n现在，找到墙上的开关。\n那个开关叫**''觉知''**。\n\n深吸一口气……按下开关！\n啪！\n光充满了房间。\n看一看，那个角落里的鬼影是什么？\n哦，那只是一件挂着的旧衣服（记忆）。\n那个可怕的声音是什么？\n哦，那只是风吹过窗户（念头）。\n\n看清楚了。\n真的是看清楚了。\n鬼影从来就不存在。只有衣服和风。\n在这个''看清''的瞬间，你需要努力去驱鬼吗？\n不需要。恐惧立刻、当下、彻底地结束了。\n这盏灯一直都在你手里。\n无论何时恐惧升起，不要跑，不要斗。\n只是开灯。\n安住在光明的真相中。"',
  E'**【练习名称：点亮的一瞬】**\n\n* **行动：** 全天保持一个"观察者"的状态。\n* **咒语：** 每当心里一紧（恐惧出现），立刻对自己说一个字：**"看！"**\n* **做法：** 这一声"看"，就是开灯。用觉知的强光照向那个念头。你会发现它像吸血鬼见光一样，瞬间化为灰烬。',
  true),

  -- Day 24
  (v_system_id, 'daily_lesson', 24, '恐惧总是关于"确定的事"',
  E'"恐惧并不是抽象的，它总是关于某些''具体事物''的。……我们不是害怕''恐惧''本身，我们是害怕失去工作、害怕生病、害怕被舆论指责。……当我们说''我很怕''时，能不能去掉''怕''这个词，直接看着那个具体的事实？……一旦你直接面对那个事实（例如：我可能会失去工作），你就能够处理它。恐惧产生于你不想面对那个事实，你想逃避它。"',
  E'1. **恐惧是"概念"与"事实"之间的距离**：\n事实是："我可能会失去工作"。恐惧是："天哪，如果我失去工作，我就完了，我会流落街头，我会很丢脸……" 我们害怕的不是事实本身，而是我们对事实的**想象**和**抗拒**。\n2. **抽象的恐惧并不存在**：\n一定要明白，你不可能害怕"空无一物"。你总是害怕**某样东西**。当你把那个模糊的"怕"字拿掉，还原为具体的"我在担心A发生"时，恐惧就从一直怪兽变成了一个待解决的问题。\n3. **直接行动**：\n面对事实，我们可以采取行动（比如去投简历，或者接受现状）。行动会消除恐惧。而面对"恐惧"这个情绪，我们往往瘫痪不动。**只要有行动，就没有恐惧。**',
  E'**【冥想主题：剥离恐怖的滤镜】**\n\n**准备阶段：** 准备好直面真相的勇气。\n\n**引导语：**\n"坐直，深呼吸。\n现在，让那个让你心神不宁的阴影浮现出来。\n你感觉很怕。\n问自己：''我到底在怕什么？具体是什么？''\n是怕别人生气？是怕钱不够用？\n把那个具体的**事实**拎出来，放在面前的桌子上。\n\n想象这个事实只是一个物体。\n比如，''钱不够用''就是一张只有数字的存折。\n''别人生气''就是一张皱着眉头的脸。\n看着这个物体。\n它本身可怕吗？它会吃人吗？\n不，它只是一个现象。\n\n现在，觉察一下，是什么给这个普通的事物加上了恐怖的滤镜？\n是你的头脑。\n头脑在说：''这太糟糕了！''''我承受不了！''\n这些声音就是滤镜。\n\n现在，把滤镜拿掉。\n把''糟糕''拿掉。把''承受不了''拿掉。\n只剩下那个事实。\n看着它。就像看着桌上的一个杯子。\n''是的，存折上的数字是这么多。''\n''是的，他的眉头是皱着的。''\n这就是全部的真相。\n在这个赤裸的真相面前，你感到恐惧吗？还是感到一种冷静的清晰？\n当你看见事实时，你的智慧就开始运作了。\n安住在这份冷静的面对中……"',
  E'**【练习名称：去形容词化】**\n\n* **行动：** 当你感到焦虑时，用纸笔写下你的恐惧。\n* **第一步：** 写下你原本的想法（例如："那个可怕的会议要来了，我肯定会搞砸，太惨了。"）\n* **第二步：** 划掉所有的**形容词**和**副词**（可怕的、肯定、太、惨）。\n* **第三步：** 读剩下的词："会议要来了。我可能会出错。"\n* **体验：** 看看去掉了情绪渲染词之后，那个"事实"是不是瞬间变得没那么吓人了？',
  true),

  -- Day 25
  (v_system_id, 'daily_lesson', 25, '对未知的恐惧',
  E'"我们常说我们害怕未知（如死亡、未来）。其实，我们并不是害怕未知，我们是害怕**失去已知**。……因为未知是不可想象的，既然无法想象，又何来恐惧？……我们真正害怕的是：失去我已经拥有的健康、我的家人、我的成就。……我们执著于''已知''，是因为我们在已知中寻找安全感。但已知是过去的、死的。只要执著于已知，恐惧就如影随形。"',
  E'1. **伪命题：害怕未知**：\n这是一个巨大的思维陷阱。你从来没有见过"未知"，你怎么会怕它呢？你怕鬼，是因为你脑子里有鬼的形象（这是已知）。你怕死，是因为你把死亡想象成了痛苦或虚无（这也是已知）。\n2. **真相：害怕失去已知**：\n我们真正害怕的，是**放手**。我们手里紧紧抓着现在的身份、财富、关系。我们害怕一旦松手，这些东西就没了。我们像抱着浮木的人，不敢游向大海。\n3. **已知是监狱**：\n我们以为"已知"让我们安全，其实"已知"让我们受困。我们在旧的记忆、旧的习惯里打转。只有当我们愿意放手，愿意踏入未知时，生命才开始流动。**不确定性，才是自由的别名。**',
  E'**【冥想主题：放开手中的浮木】**\n\n**准备阶段：** 想象自己在茫茫大海上。\n\n**引导语：**\n"深呼吸……\n想象你漂浮在一望无际的大海上。\n你的怀里紧紧抱着一根浮木。这根浮木就是你的''已知''——你的工作，你的家庭，你的名声，你的过去。\n你死死抱着它，因为你觉得一旦松手，你就会淹死。\n你的肌肉因为紧张而僵硬，你的心里充满了''怕松手''的恐惧。\n\n现在，看看四周的大海。\n海水温暖、深邃、充满浮力。\n大海代表着''未知''，代表着生命的无限可能。\n大海并没有要伤害你，它托举着你。\n\n现在，做一个生平最大胆的决定。\n**松开那根浮木。**\n推开它。让它飘走。\n你现在什么抓手都没有了。\n你沉下去了吗？没有。\n海水温柔地托住了你。\n你可以自由地仰泳，自由地划水。\n你不再被困在那根木头旁边。你可以去任何地方。\n\n在这个一无所有的时刻，去感受那份巨大的释放感。\n没有了''已知''的负担，你变得无比轻盈。\n你不再需要保护什么，因为你什么都没有。\n你拥抱了整个未知。\n告诉自己：''我很安全。未知是我的朋友。''\n安住在这种漂浮的自由中……"',
  E'**【练习名称：走新路】**\n\n* **行动：** 在物理层面打破"已知"。\n* **做法：**\n  * 下班回家时，故意走一条**完全陌生**的路。\n  * 去餐厅点一道你**从来没吃过**（甚至不知道是什么）的菜。\n* **觉察：** 观察在面对陌生时，内心那一瞬间的微小不安。然后，享受那种"探险"的新鲜感。告诉自己："未知并不可怕，它很有趣。"',
  true),

  -- Day 26
  (v_system_id, 'daily_lesson', 26, '我不重要',
  E'"只要有''我''，就有恐惧。……''我''想变成大人物，''我''怕失败，''我''怕被瞧不起。……这个''我''是一切焦虑的中心。……能不能试着体会一下''完全不重要''的感觉？像路边的一块石头，像风中的一片叶子。……当你想成为''什么''(Something)时，恐惧就来了；当你甘愿''什么都不是''(Nothing)时，恐惧在哪里？"',
  E'1. **重要性即负担**：\n我们花了一辈子的时间来证明"我很重要"。我们追求头衔、赞美、影响力。这种"重要感"就像我们要顶在头上的瓷花瓶，越贵重，我们走起路来就越战战兢兢，生怕碎了。\n2. **无我即无畏**：\n如果你是一粒尘埃，你会怕摔下来吗？不会，因为你已经在地上。如果你是空气，你会怕被刀砍吗？不会。只有当你是"某个人物"时，你才有软肋。\n3. **Nothingness 的力量**：\n这不是自卑，而是一种极度的自信。因为我不依靠任何外在标签来定义自己，所以我无懈可击。我愿意默默无闻，我愿意被遗忘。在那份寂静的谦卑中，没有任何恐惧能立足。',
  E'**【冥想主题：尘埃之舞】**\n\n**准备阶段：** 彻底的放松和放下。\n\n**引导语：**\n"坐下来，把你的''身份''脱在门外。\n深呼吸……\n想象你是一粒微小的尘埃，漂浮在阳光里。\n你没有名字，没有历史，没人知道你，也没人在乎你。\n你甚至不需要去哪里。你只是随着风起舞。\n\n看看下面的人群，他们在忙着争名夺利，忙着证明自己。\n而你在空中看着，感到一种深深的悲悯和轻松。\n你不需要维护什么形象。\n别人骂你，你只是一粒尘埃，骂声穿过你。\n别人夸你，你只是一粒尘埃，夸奖挂不住你。\n\n感受一下这种''彻底不重要''的感觉。\n是不是有一种卸下千斤重担的解脱？\n不需要紧绷，不需要表演，不需要防御。\n你与万物平等。\n你与光同在。\n在这种极度的微小中，你触碰到了无限。\n对自己说：''我什么都不是。我自由了。''\n安住在这份轻盈的虚空中……"',
  E'**【练习名称：隐形人实验】**\n\n* **场景：** 在公司会议或聚会中。\n* **惯性：** 我们通常想发言、想刷存在感、想让别人注意自己。\n* **挑战：** **做一天隐形人**。\n* **做法：** 不主动发言，不试图引起注意。静静地听，静静地看。\n* **心态：** 享受这种"我在场，但我不需要证明我在场"的轻松。观察那些拼命想证明自己的人，你会看到那是多么累的一场戏。',
  true),

  -- Day 27
  (v_system_id, 'daily_lesson', 27, '恐惧消耗能量',
  E'"恐惧是能量最大的消耗者。……当你在恐惧中时，你的身体是僵硬的，你的神经是紧绷的，你的心智是混乱的。……为了压抑恐惧，我们又消耗了另一半能量。……如果我们能从恐惧中解脱，这股巨大的能量就会释放出来。这股能量就是智慧，就是爱。"',
  E'1. **恐惧是精神的漏洞**：\n就像手机后台运行的高耗能程序，恐惧即使在潜意识里运作（隐隐的焦虑），也会迅速耗干你的电量。你觉得累，往往不是因为体力劳动，而是因为这种心理上的紧绷。\n2. **压抑的代价**：\n我们不仅怕，还要装作不怕。这种"装"需要巨大的能量来维持面具。我们的大部分精力都用在了内耗上，所以我们没有精力去创造，去爱，去感知美。\n3. **能量的回收**：\n如果你不再怕了，那些用来防御、伪装、焦虑的能量去哪了？它们不会消失，它们会回流。你会突然觉得自己精力充沛，眼明心亮。这股回流的能量，就是**热情**。',
  E'**【冥想主题：解冻冰封的河流】**\n\n**准备阶段：** 扫描身体的僵硬区域。\n\n**引导语：**\n"闭上眼。扫描你的身体。\n肩膀是不是耸着的？胃是不是紧的？牙关是不是咬着的？\n这些紧绷的地方，就是恐惧冻结能量的地方。\n恐惧像严冬一样，把你体内的生命之河冻住了。\n\n现在，把觉知的阳光照向这些冰块。\n从肩膀开始……告诉它：''即使现在不安全，我也允许你放松。''\n呼气，看着肩膀的冰融化成水，流下来。\n再照向胃部……''不需要抓紧，松开。''\n看着胃部的结解开，暖流开始转动。\n\n随着每一个部位的放松，你感觉到一种酥麻的电流感。\n那是被释放出来的能量。\n它原本被锁在恐惧里，现在它自由了。\n它在你的血管里奔跑，它让你的指尖发热。\n你的身体变软了，但你的精神变强了。\n\n想象这股解冻后的能量，汇聚成一条大河，浩浩荡荡地流向大海。\n没有任何东西能阻挡它。\n这就是你原本的生命力。\n享受这份充沛的活力。\n你是流动的，你是不可阻挡的。"',
  E'**【练习名称：微观放松】**\n\n* **行动：** 设置手机闹钟，每隔1小时提醒一次。\n* **做法：** 闹钟响时，只做一件事：**检查并放下肩膀**，**松开下巴**。\n* **口诀：** "松开。电量回收。"\n* **体验：** 这种物理上的松弛，会直接向大脑发送"我很安全"的信号，瞬间切断恐惧的耗能回路。',
  true),

  -- Day 28
  (v_system_id, 'daily_lesson', 28, '依赖与恐惧的共生',
  E'"只要有依赖，就一定有恐惧。……我依赖你给我快乐，给我安全感，我就必然会恐惧失去你。……因此，依赖不是爱，依赖是恐惧的温床。……若想没有恐惧，必须切断对他人的心理依赖。……这并不意味着我们要切断关系，而是要在关系中保持内在的独立与完整。"',
  E'1. **连体婴的痛苦**：\n心理依赖就像连体婴。如果我不依附于你，我就无法生存。这种状态下，怎么可能有快乐？只有时刻担心被分离的恐慌。\n2. **切断依赖不是切断联系**：\n这很重要。克氏不是让你离家出走、抛妻弃子。他是让你切断**心理上**那种"没有你我就活不下去"的执念。你可以和伴侣生活在一起，但你的快乐源泉是你自己，而不是他。\n3. **独立才能无惧**：\n当你是一个圆满的圆，而不是半个圆时，你就不怕别人滚走了。你依然可以和他在一起滚动，那是共舞；但他走了，你依然可以转动。',
  E'**【冥想主题：收回投射的光】**\n\n**准备阶段：** 想象自己身上有许多光线连着别人。\n\n**引导语：**\n"坐直。闭上眼。\n想象你的心像一个发光体。\n但你的光并没有照亮自己，而是投射到了别人身上。\n有一束光投射在伴侣身上（寻找爱），有一束投射在老板身上（寻找肯定），有一束投射在孩子身上（寻找寄托）。\n因为光都投射出去了，你的中心是暗淡的、虚弱的。\n你害怕他们离开，因为他们一走，你的光就没了。\n\n现在，做一次能量的回收。\n吸气……想象把那束投在伴侣身上的光，慢慢收回来。\n告诉自己：''收回我对爱的乞求。爱在我这里。''\n再吸气……把投在外界的光都收回来。\n''收回我对安全的乞求。安全在我这里。''\n\n随着光线的回收，感觉你的中心越来越亮，越来越热。\n你不再是一个空壳。你变成了一个小太阳。\n你不需要向外抓取温暖，你自己就是热源。\n\n现在，再次看向那些人。\n你依然可以用光照耀他们，那是**给予**，不再是**依赖**。\n你不再怕他们离开。因为光源在你这里。\n感受这份自给自足的安稳。\n这就是无惧的根基。"',
  E'**【练习名称：我能搞定】**\n\n* **场景：** 当遇到困难，第一反应想求助或抱怨时。\n* **行动：** **暂停求助**。\n* **尝试：** 先尝试自己解决，或者自己安抚自己的情绪。\n* **内语：** "我有力量面对这个。我不需要拐杖。"\n* **体验：** 每一次你独自跨过一道坎，你对自己的信任就增加一分，恐惧就减少一分。',
  true),

  -- Day 29
  (v_system_id, 'daily_lesson', 29, '面对死亡',
  E'"我们害怕死亡，是因为我们不知道死亡是什么。……我们执著于已知的生活，执著于''我''的延续。……死亡意味着''已知''的终结。……如果我们能每天都死于昨天，每天都终结所有的烦恼、恨意和执著，那么死亡就不再可怕。……只有死于过去，才有真正的新生。……能不能在活着的时候，就体验死亡？"',
  E'1. **死亡即终结**：\n死亡是最大的恐惧。但死亡到底是什么？它是**终结**。终结你的记忆、你的财产、你的关系。我们怕的不是肉体的消失，而是"我"的消失。\n2. **每天都在死**：\n如果你等到呼吸停止那天才面对死亡，那就太晚了。克氏提倡一种**"心理上的死亡"**。每天晚上，把今天的烦恼、成就、身份，统统终结掉。不要带到明天。这种"清空"，就是死亡的预演。\n3. **死与生是一体的**：\n只有把杯子里的陈水倒空（死），才能装进新鲜的水（生）。一个不敢"死于昨天"的人，其实从来没有真正"活在今天"。他只是个活死人，背着尸体（记忆）行走。**向死而生，方为真生。**',
  E'**【冥想主题：小小的死亡】**\n\n**准备阶段：** 睡前进行最佳。躺在床上，像躺在墓穴里。\n\n**引导语：**\n"躺平，放松全身，直到感觉身体沉重得像一块石头。\n今晚，我们要练习一次''小小的死亡''。\n深呼吸……想象你的生命即将在这一刻结束。\n\n回顾这一天。\n你争执过的事，现在还重要吗？**放下。**\n你赚到的钱，现在能带走吗？**放下。**\n你的身份、名字、骄傲，现在还有意义吗？**放下。**\n想象这一切都像烟雾一样从你身上飘散。\n\n你现在一无所有。\n这具身体也即将回归大地。\n看着这个''空无''。\n可怕吗？还是说，这其实是一种极度的宁静？\n没有了负担，没有了''我必须怎样''的压力。\n只有纯粹的寂静。\n\n在这个寂静中，你与宇宙合一了。\n这就是死亡。它不是毁灭，它是回归。\n允许自己在这个''空''里安息。\n明天早上，当阳光唤醒你时，你将是一个全新的人。\n一个没有过去的人。\n一个重生的婴儿。\n晚安，旧的自己。"',
  E'**【练习名称：清理遗物】**\n\n* **行动：** 整理一个抽屉或角落。\n* **心态：** 想象如果你明天就不在了，这些东西对你还有意义吗？\n* **做法：** 扔掉那些没用的、只代表过去记忆的东西。\n* **体验：** 每扔掉一样东西，就体验一次"我不需要它也能活"的轻松。这是物理层面的"死于过去"。',
  true),

  -- Day 30
  (v_system_id, 'daily_lesson', 30, '恐惧的彻底止息',
  E'"恐惧的终结不是一个渐进的过程。……你不能说''我会慢慢变得不害怕''。……时间是恐惧的朋友。……必须在当下这一刻，全神贯注地看着恐惧，看穿它的整个结构（时间、思想、自我）。……就在这顿悟的一瞬间，恐惧彻底止息了。……这是一种突变，一种心理上的爆炸。"',
  E'1. **没有渐进**：\n不要试图一点点砍掉恐惧的尾巴，它会长出来的。要砍就砍头。恐惧的头就是"时间感"。\n2. **顿悟 (Insight)**：\n恐惧的终结来自于**看见真相**。就像你误以为绳子是蛇，你会怕。当你**看清**那是绳子的一瞬间，恐惧是慢慢消失的吗？不是，是**立刻**消失的。\n3. **全神贯注 (Total Attention)**：\n要把绳子看清楚，需要光。这个光就是你全部的注意力。当你不再逃避、不再分析，而是用全部的生命能量去注视恐惧时，那个高能量的"看"，会瞬间烧毁恐惧的幻象。',
  E'**【冥想主题：激光般的注视】**\n\n**准备阶段：** 调动全身的能量。\n\n**引导语：**\n"坐直。这不仅是冥想，这是决战。\n把你的恐惧召唤出来。无论是对什么的恐惧。\n让它站在你面前。\n\n现在，把你所有的注意力——视觉、听觉、感觉、思维——全部汇聚起来。\n像凸透镜聚焦阳光一样，汇聚成一个点。\n这束高能量的光，直接照在恐惧的脸上。\n\n不要眨眼。不要思考。只是看！\n看它的核心是什么？\n它是思想制造的影子。\n它是对未来的妄想。\n它是虚无的！\n\n保持这种高强度的注视。\n在这种强光下，影子能生存吗？\n你会看到它开始扭曲、变淡、瓦解。\n就像雪花落在了烧红的铁板上。\n**嘶——**\n没了。\n\n不是你赶走了它，是它在真相面前无法立足。\n深呼吸……\n感受那种战场清理后的空旷与清明。\n你赢了。不是靠战斗，是靠觉醒。\n这就是解脱。"',
  E'**【练习名称：当下一喝】**\n\n* **场景：** 当恐惧念头像苍蝇一样嗡嗡叫时。\n* **行动：** 像禅师一样，在心里大喝一声：**"停！"** 或者 **"醒来！"**\n* **效果：** 这声断喝能瞬间切断思维的惯性，把你强行拉回当下的感官。在那个被打断的瞬间，你会体验到没有恐惧的空白。那就是自由的缝隙。',
  true),

  -- Day 31
  (v_system_id, 'daily_lesson', 31, '总复盘——这世界需要无惧的人',
  E'"一个无惧的人，才是一个真正的人。……只有当恐惧止息，爱才能进来。……我们的社会建立在恐惧之上（法律、道德、竞争）。……如果你能从恐惧中解脱，你就给这个世界带来了一份巨大的礼物。……你将成为一盏灯，照亮你自己，也照亮周围。……这就是从依赖走向自由的旅程。"',
  E'1. **恐惧与爱不共存**：\n三月的总结。如果心里有怕（怕失去、怕受伤），就不可能有爱。恐惧是紧缩，爱是敞开。只有清除了恐惧的杂草，爱的花朵才能开放。\n2. **个人的责任**：\n我们不仅为自己修行，也为世界。一个充满恐惧的人，会制造混乱、战争和隔阂。一个无惧的人，他的存在本身就是和平。\n3. **点灯者**：\n从依赖（向外求光）到无惧（自己发光）。这就是三月旅程的终点。你不再需要上师、书本或伴侣来给你安全感。**你就是安全感本身。**',
  E'**【冥想主题：成为光源】**\n\n**准备阶段：** 带着感恩和庆祝的心情。\n\n**引导语：**\n"坐直。回望这一个月。\n我们看清了依赖的拐杖，看清了执著的锁链，看清了恐惧的阴影。\n我们把它们一一拆解。\n\n现在，感受你的内心。\n那里不再拥挤，不再黑暗。\n那里有一片广阔的空间。\n在这个空间的中央，有一盏灯亮了。\n这盏灯不需要燃油，它靠觉知燃烧。\n\n吸气，让灯光变亮。\n呼气，让光芒穿透你的身体，射向四面八方。\n在这光中，没有阴影。\n在这光中，没有分离。\n你就是这光。\n\n对着这个世界说：''我不再向你乞求安全。我来这里，是为了分享我的平安。''\n''我不再是那个瑟瑟发抖的乞丐，我是富足的给予者。''\n感受这份力量。\n它是安静的，但它是不可战胜的。\n带着这盏灯，走进四月，走进欲望与热情的火焰中。\n你准备好了。"',
  E'**【练习名称：三月的毕业证书】**\n\n* **行动：** 写下一句你这个月最深刻的感悟。\n* **例子：** "恐惧是思想的影子"、"我就是我所寻找的安全感"。\n* **仪式：** 把它设为手机壁纸，或者贴在镜子上。提醒自己：**我已经醒来，我不再回去。**',
  true);

END $$;
